+/**
+ * SMS-specific notification settings.
+ *
+ * SMS is opt-in by default because it requires a phone number and incurs
+ * per-message cost. Unlike email, there is no frequency/batching — SMS
+ * notifications are always delivered instantly when enabled.
+ */
+export interface SmsPreferences {
+  /** Whether SMS notifications are enabled. Defaults to false (opt-in). */
+  enabled: boolean;
+  /** The user's phone number in E.164 format (e.g., +15551234567). */
+  phoneNumber: string;
+  /** Notification types the user is subscribed to via SMS. */
+  subscribedCategories: NotificationType[];
+}
+
+/**
+ * Webhook-specific notification settings.
+ *
+ * Webhook is opt-in by default because it requires a valid URL endpoint.
+ */
+export interface WebhookPreferences {
+  /** Whether webhook notifications are enabled. Defaults to false (opt-in). */
+  enabled: boolean;
+  /** The webhook URL to deliver notifications to. */
+  url: string;
+  /** Notification types the user is subscribed to via webhook. */
+  subscribedCategories: NotificationType[];
+}
+
