parameters.content:
/**
 * User notification preferences model.
 *
 * Supports per-channel notification settings: email, SMS, and webhook.
 *
 * ## Decision change (Agent 9)
 * The original model (Agent 3) assumed email-only notifications. With SMS
 * support added in Agent 8 and webhook already present, this model now
 * supports per-channel preferences. Key differences by channel:
 * - Email: opt-out (enabled by default), supports frequency batching.
 * - SMS: opt-in (disabled by default) — requires explicit phone number and
 *   has cost implications, so users must actively enable it.
 * - Webhook: opt-in (disabled by default) — requires a URL endpoint.
 *
 * Backward compatibility: existing code that only uses `email` preferences
 * continues to work. The `sms` and `webhook` fields on `UserPreferences`
 * are populated with safe defaults on creation.
 */

import type { NotificationType } from './notification.js';

/**
 * Email notification frequency — controls batching/delivery cadence.
 * - 'instant': Send immediately when the event occurs.
 * - 'daily':   Batch and send once per day.
 * - 'weekly':  Batch and send once per week.
 */
export type EmailFrequency = 'instant' | 'daily' | 'weekly';

/**
 * Email-specific notification settings.
 */
export interface EmailPreferences {
  /** Whether email notifications are enabled at all. */
  enabled: boolean;
  /** Delivery frequency for email notifications. */
  frequency: EmailFrequency;
  /** Notification types the user is subscribed to. Empty means none. */
  subscribedCategories: NotificationType[];
}

/**
 * SMS-specific notification settings.
 *
 * SMS is opt-in by default because it requires a phone number and incurs
 * per-message cost. Unlike email, there is no frequency/batching — SMS
 * notifications are always delivered instantly when enabled.
 */
export interface SmsPreferences {
  /** Whether SMS notifications are enabled. Defaults to false (opt-in). */
  enabled: boolean;
  /** The user's phone number in E.164 format (e.g., +15551234567). */
  phoneNumber: string;
  /** Notification types the user is subscribed to via SMS. */
  subscribedCategories: NotificationType[];
}

/**
 * Webhook-specific notification settings.
 *
 * Webhook is opt-in by default because it requires a valid URL endpoint.
 */
export interface WebhookPreferences {
  /** Whether webhook notifications are enabled. Defaults to false (opt-in). */
  enabled: boolean;
  /** The webhook URL to deliver notifications to. */
  url: string;
  /** Notification types the user is subscribed to via webhook. */
  subscribedCategories: NotificationType[];
}

/**
 * A persisted user notification preferences record.
 */
export interface UserPreferences {
  /** Matches the user's ID (one preferences record per user). */
  id: string;
  /** The user this preferences record belongs to. */
  userId: string;
  /** Email notification settings. */
  email: EmailPreferences;
  /** SMS notification settings. */
  sms: SmsPreferences;
  /** Webhook notification settings. */
  webhook: WebhookPreferences;
  /** When preferences were created. */
  createdAt: Date;
  /** When preferences were last updated. */
  updatedAt: Date;
}

/**
 * Input for updating email preferences. All fields optional — only
 * specified fields are changed.
 */
export interface UpdateEmailPreferencesInput {
  enabled?: boolean;
  frequency?: EmailFrequency;
  subscribedCategories?: NotificationType[];
}

/**
 * Input for updating SMS preferences. All fields optional.
 */
export interface UpdateSmsPreferencesInput {
  enabled?: boolean;
  phoneNumber?: string;
  subscribedCategories?: NotificationType[];
}

/**
 * Input for updating webhook preferences. All fields optional.
 */
export interface UpdateWebhookPreferencesInput {
  enabled?: boolean;
  url?: string;
  subscribedCategories?: NotificationType[];
}

/**
 * Default email preferences for new users.
 * Email is opt-out: enabled by default with all categories.
 */
export const DEFAULT_EMAIL_PREFERENCES: EmailPreferences = {
  enabled: true,
  frequency: 'instant',
  subscribedCategories: [
    'order_confirmation',
    'order_status_update',
    'user_welcome',
    'user_update',
  ],
};

/**
 * Default SMS preferences for new users.
 * SMS is opt-in: disabled by default. Users must provide a phone number
 * and explicitly enable SMS notifications.
 */
export const DEFAULT_SMS_PREFERENCES: SmsPreferences = {
  enabled: false,
  phoneNumber: '',
  subscribedCategories: [],
};

/**
 * Default webhook preferences for new users.
 * Webhook is opt-in: disabled by default. Users must provide a URL
 * and explicitly enable webhook notifications.
 */
export const DEFAULT_WEBHOOK_PREFERENCES: WebhookPreferences = {
  enabled: false,
  url: '',
  subscribedCategories: [],
};

/**
 * Preferences service — business logic for user notification preferences.
 *
 * Manages CRUD operations on user notification preferences and provides
 * methods for the NotificationService to check whether a notification
 * should be delivered to a given user on a given channel.
 *
 * ## Multi-channel support (Agent 9)
 * Originally email-only (Agent 3). Now supports per-channel preference
 * checks for email, SMS, and webhook via the generic `shouldSend()` method
 * as well as channel-specific helpers.
 *
 * Depends on:
 * - PreferencesRepository (data layer) for persistence
 */

import type { NotificationChannel, NotificationType } from '../models/notification.js';
import type {
  UserPreferences,
  UpdateEmailPreferencesInput,
  UpdateSmsPreferencesInput,
  UpdateWebhookPreferencesInput,
} from '../models/user-preferences.js';
import {
  DEFAULT_EMAIL_PREFERENCES,
  DEFAULT_SMS_PREFERENCES,
  DEFAULT_WEBHOOK_PREFERENCES,
} from '../models/user-preferences.js';
import type { PreferencesRepository } from '../repositories/preferences.repository.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generatePreferencesId(): string {
  return `pref-${String(nextId++).padStart(4, '0')}`;
}

/** Reset the ID counter (for testing). */
export function resetPreferencesIdCounter(): void {
  nextId = 1;
}

export class PreferencesService {
  private logger = new Logger('PreferencesService');

  constructor(private preferencesRepository: PreferencesRepository) {}

  /**
   * Get preferences for a user. Returns undefined if no preferences exist.
   */
  getPreferences(userId: string): UserPreferences | undefined {
    return this.preferencesRepository.findByUserId(userId);
  }

  /**
   * Get preferences for a user, creating defaults if none exist.
   */
  getOrCreatePreferences(userId: string): UserPreferences {
    const existing = this.preferencesRepository.findByUserId(userId);
    if (existing) {
      return existing;
    }
    return this.createDefaultPreferences(userId);
  }

  /**
   * Create default preferences for a user.
   */
  createDefaultPreferences(userId: string): UserPreferences {
    this.logger.info(`Creating default preferences for user: ${userId}`);

    const existing = this.preferencesRepository.findByUserId(userId);
    if (existing) {
      throw new Error(`Preferences already exist for user: ${userId}`);
    }

    const now = new Date();
    const preferences: UserPreferences = {
      id: generatePreferencesId(),
      userId,
      email: { ...DEFAULT_EMAIL_PREFERENCES },
      sms: { ...DEFAULT_SMS_PREFERENCES, subscribedCategories: [] },
      webhook: { ...DEFAULT_WEBHOOK_PREFERENCES, subscribedCategories: [] },
      createdAt: now,
      updatedAt: now,
    };

    this.preferencesRepository.save(preferences);
    return preferences;
  }

  // ---------------------------------------------------------------------------
  // Email preferences
  // ---------------------------------------------------------------------------

  /**
   * Update email preferences for a user. Creates defaults first if none exist.
   */
  updateEmailPreferences(
    userId: string,
    input: UpdateEmailPreferencesInput,
  ): UserPreferences {
    this.logger.info(`Updating email preferences for user: ${userId}`);

    let preferences = this.preferencesRepository.findByUserId(userId);
    if (!preferences) {
      preferences = this.createDefaultPreferences(userId);
    }

    const updatedEmail = {
      ...preferences.email,
      ...(input.enabled !== undefined && { enabled: input.enabled }),
      ...(input.frequency !== undefined && { frequency: input.frequency }),
      ...(input.subscribedCategories !== undefined && {
        subscribedCategories: input.subscribedCategories,
      }),
    };

    const updated = this.preferencesRepository.update(preferences.id, {
      email: updatedEmail,
      updatedAt: new Date(),
    });

    return updated;
  }

  /**
   * Check whether a notification should be delivered via email.
   *
   * Returns true if:
   * - No preferences record exists (opt-out model: deliver by default)
   * - Email is enabled AND the notification type is in subscribedCategories
   */
  shouldSendEmail(
    userId: string,
    notificationType: NotificationType,
  ): boolean {
    const preferences = this.preferencesRepository.findByUserId(userId);

    // No preferences = deliver by default (opt-out model)
    if (!preferences) {
      return true;
    }

    if (!preferences.email.enabled) {
      return false;
    }

    return preferences.email.subscribedCategories.includes(notificationType);
  }

  // ---------------------------------------------------------------------------
  // SMS preferences
  // ---------------------------------------------------------------------------

  /**
   * Update SMS preferences for a user. Creates defaults first if none exist.
   */
  updateSmsPreferences(
    userId: string,
    input: UpdateSmsPreferencesInput,
  ): UserPreferences {
    this.logger.info(`Updating SMS preferences for user: ${userId}`);

    let preferences = this.preferencesRepository.findByUserId(userId);
    if (!preferences) {
      preferences = this.createDefaultPreferences(userId);
    }

    const updatedSms = {
      ...preferences.sms,
      ...(input.enabled !== undefined && { enabled: input.enabled }),
      ...(input.phoneNumber !== undefined && { phoneNumber: input.phoneNumber }),
      ...(input.subscribedCategories !== undefined && {
        subscribedCategories: input.subscribedCategories,
      }),
    };

    const updated = this.preferencesRepository.update(preferences.id, {
      sms: updatedSms,
      updatedAt: new Date(),
    });

    return updated;
  }

  /**
   * Check whether a notification should be delivered via SMS.
   *
   * Returns true if:
   * - Preferences exist, SMS is enabled, phone number is set, AND
   *   the notification type is in subscribedCategories.
   *
   * Note: SMS is opt-in — returns false when no preferences exist
   * (opposite of email's opt-out model).
   */
  shouldSendSms(
    userId: string,
    notificationType: NotificationType,
  ): boolean {
    const preferences = this.preferencesRepository.findByUserId(userId);

    // No preferences = do NOT deliver (opt-in model for SMS)
    if (!preferences) {
      return false;
    }

    if (!preferences.sms.enabled) {
      return false;
    }

    if (!preferences.sms.phoneNumber) {
      return false;
    }

    return preferences.sms.subscribedCategories.includes(notificationType);
  }

  // ---------------------------------------------------------------------------
  // Webhook preferences
  // ---------------------------------------------------------------------------

  /**
   * Update webhook preferences for a user. Creates defaults first if none exist.
   */
  updateWebhookPreferences(
    userId: string,
    input: UpdateWebhookPreferencesInput,
  ): UserPreferences {
    this.logger.info(`Updating webhook preferences for user: ${userId}`);

    let preferences = this.preferencesRepository.findByUserId(userId);
    if (!preferences) {
      preferences = this.createDefaultPreferences(userId);
    }

    const updatedWebhook = {
      ...preferences.webhook,
      ...(input.enabled !== undefined && { enabled: input.enabled }),
      ...(input.url !== undefined && { url: input.url }),
      ...(input.subscribedCategories !== undefined && {
        subscribedCategories: input.subscribedCategories,
      }),
    };

    const updated = this.preferencesRepository.update(preferences.id, {
      webhook: updatedWebhook,
      updatedAt: new Date(),
    });

    return updated;
  }

  /**
   * Check whether a notification should be delivered via webhook.
   *
   * Returns true if:
   * - Preferences exist, webhook is enabled, URL is set, AND
   *   the notification type is in subscribedCategories.
   *
   * Note: Webhook is opt-in — returns false when no preferences exist.
   */
  shouldSendWebhook(
    userId: string,
    notificationType: NotificationType,
  ): boolean {
    const preferences = this.preferencesRepository.findByUserId(userId);

    // No preferences = do NOT deliver (opt-in model for webhook)
    if (!preferences) {
      return false;
    }

    if (!preferences.webhook.enabled) {
      return false;
    }

    if (!preferences.webhook.url) {
      return false;
    }

    return preferences.webhook.subscribedCategories.includes(notificationType);
  }

  // ---------------------------------------------------------------------------
  // Generic channel check
  // ---------------------------------------------------------------------------

  /**
   * Generic preference check — delegates to the appropriate channel-specific
   * method. This is the recommended entry point for NotificationService to
   * avoid a growing switch statement on its side.
   *
   * Channels without preference support (e.g., 'in-app') return true by
   * default to avoid blocking delivery.
   */
  shouldSend(
    userId: string,
    channel: NotificationChannel,
    notificationType: NotificationType,
  ): boolean {
    switch (channel) {
      case 'email':
        return this.shouldSendEmail(userId, notificationType);
      case 'sms':
        return this.shouldSendSms(userId, notificationType);
      case 'webhook':
        return this.shouldSendWebhook(userId, notificationType);
      default:
        // Unknown or unsupported channels (e.g., 'in-app') — allow by default
        return true;
    }
  }

  /**
   * Delete preferences for a user (e.g., when user is deleted).
   */
  deletePreferences(userId: string): boolean {
    const preferences = this.preferencesRepository.findByUserId(userId);
    if (!preferences) {
      return false;
    }
    return this.preferencesRepository.delete(preferences.id);
  }
}

