      expect(prefs.webhook.enabled).toBe(false);
      expect(prefs.webhook.url).toBe('https://hooks.example.com/notify');
    });
  });

  describe('shouldSendWebhook', () => {
    it('should return false when no preferences exist (opt-in model)', () => {
      expect(
        service.shouldSendWebhook('user-0001', 'order_confirmation'),
      ).toBe(false);
    });

    it('should return false when webhook is disabled', () => {
