describe('NotificationService with preferences', () => {
  let db: Database;
  let eventBus: EventBus;
  let notificationService: NotificationService;
  let preferencesService: PreferencesService;
  let emailAdapter: EmailAdapter;

  const orderCreatedEvent: OrderCreatedEvent = {
    type: 'order:created',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [
        { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
      ],
      total: 10,
      status: 'pending',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    user: {
      id: 'user-1',
      name: 'Alice',
      email: 'alice@example.com',
      role: 'member',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    timestamp: new Date(),
  };

  beforeEach(() => {
    db = new Database();
    eventBus = new EventBus();
    notificationService = new NotificationService(eventBus);
    emailAdapter = new EmailAdapter(eventBus);
    notificationService.registerAdapter(emailAdapter);

    const repository = new PreferencesRepository(db);
    preferencesService = new PreferencesService(repository);
    notificationService.setPreferencesService(preferencesService);

    resetNotificationIdCounter();
    resetPreferencesIdCounter();
  });

  it('should deliver notification when no preferences exist', async () => {
    await eventBus.emit(orderCreatedEvent);

    expect(notificationService.getNotificationCount()).toBe(1);
  });

  it('should deliver notification when user has default preferences', async () => {
    preferencesService.createDefaultPreferences('alice@example.com');
    await eventBus.emit(orderCreatedEvent);

    expect(notificationService.getNotificationCount()).toBe(1);
  });

  it('should suppress notification when email is disabled', async () => {
    preferencesService.createDefaultPreferences('alice@example.com');
    preferencesService.updateEmailPreferences('alice@example.com', {
      enabled: false,
    });

    await eventBus.emit(orderCreatedEvent);

    expect(notificationService.getNotificationCount()).toBe(0);
    expect(emailAdapter.getSentEmails()).toHaveLength(0);
  });

  it('should suppress notification when category is unsubscribed', async () => {
    preferencesService.createDefaultPreferences('alice@example.com');
    preferencesService.updateEmailPreferences('alice@example.com', {
      subscribedCategories: ['user_welcome'],
    });

    await eventBus.emit(orderCreatedEvent);

    expect(notificationService.getNotificationCount()).toBe(0);
  });

  it('should deliver notification when category is subscribed', async () => {
    preferencesService.createDefaultPreferences('alice@example.com');
    preferencesService.updateEmailPreferences('alice@example.com', {
      subscribedCategories: ['order_confirmation'],
    });

    await eventBus.emit(orderCreatedEvent);

    expect(notificationService.getNotificationCount()).toBe(1);
  });
});

describe('NotificationService multi-channel preference checks', () => {
  let db: Database;
  let eventBus: EventBus;
  let notificationService: NotificationService;
  let preferencesService: PreferencesService;
  let smsAdapter: SmsAdapter;

  beforeEach(() => {
    db = new Database();
    eventBus = new EventBus();
    notificationService = new NotificationService(eventBus);
    smsAdapter = new SmsAdapter(eventBus);
    notificationService.registerAdapter(smsAdapter);

    const repository = new PreferencesRepository(db);
    preferencesService = new PreferencesService(repository);
    notificationService.setPreferencesService(preferencesService);

    resetNotificationIdCounter();
    resetPreferencesIdCounter();
  });

  it('should suppress SMS when user has no preferences (opt-in model)', async () => {
    // Manually emit a notification:send-triggering event via the service's
    // internal dispatch. We do this by emitting an order:created event that
    // the notification service handles — but the default handler sends email.
    // Instead, we test the preferences logic directly through shouldSend.
    expect(
      preferencesService.shouldSend('+15551234567', 'sms', 'order_confirmation'),
    ).toBe(false);
  });

  it('should allow SMS when user has opted in with phone and category', () => {
    preferencesService.createDefaultPreferences('+15551234567');
    preferencesService.updateSmsPreferences('+15551234567', {
      enabled: true,
      phoneNumber: '+15551234567',
      subscribedCategories: ['order_confirmation'],
    });

    expect(
      preferencesService.shouldSend('+15551234567', 'sms', 'order_confirmation'),
    ).toBe(true);
  });

  it('should suppress webhook when user has no preferences (opt-in model)', () => {
    expect(
      preferencesService.shouldSend(
        'https://hooks.example.com',
        'webhook',
        'order_confirmation',
      ),
    ).toBe(false);
  });

  it('should allow webhook when user has opted in with URL and category', () => {
    preferencesService.createDefaultPreferences('user-0001');
    preferencesService.updateWebhookPreferences('user-0001', {
      enabled: true,
      url: 'https://hooks.example.com/notify',
      subscribedCategories: ['order_confirmation'],
    });

    expect(
      preferencesService.shouldSend('user-0001', 'webhook', 'order_confirmation'),
    ).toBe(true);
  });
});

/**
 * Repository for UserPreferences data access.
 *
 * Extends BaseRepository with preferences-specific query methods.
 * Each user has at most one preferences record (keyed by userId).
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { UserPreferences } from '../models/user-preferences.js';
import type { NotificationType } from '../models/notification.js';
import type { EmailFrequency } from '../models/user-preferences.js';
import { DEFAULT_SMS_PREFERENCES, DEFAULT_WEBHOOK_PREFERENCES } from '../models/user-preferences.js';
import { BaseRepository } from './base.repository.js';

export class PreferencesRepository extends BaseRepository<UserPreferences> {
  constructor(db: Database) {
    super(db, 'user_preferences');
  }

  protected toDomain(record: DatabaseRecord): UserPreferences {
    return {
      id: record['id'] as string,
      userId: record['userId'] as string,
      email: {
        enabled: record['emailEnabled'] as boolean,
        frequency: record['emailFrequency'] as EmailFrequency,
        subscribedCategories: JSON.parse(
          record['emailSubscribedCategories'] as string,
        ) as NotificationType[],
      },
      sms: record['smsEnabled'] !== undefined
        ? {
            enabled: record['smsEnabled'] as boolean,
            phoneNumber: record['smsPhoneNumber'] as string,
            subscribedCategories: JSON.parse(
              record['smsSubscribedCategories'] as string,
            ) as NotificationType[],
          }
        : { ...DEFAULT_SMS_PREFERENCES },
      webhook: record['webhookEnabled'] !== undefined
        ? {
            enabled: record['webhookEnabled'] as boolean,
            url: record['webhookUrl'] as string,
            subscribedCategories: JSON.parse(
              record['webhookSubscribedCategories'] as string,
            ) as NotificationType[],
          }
        : { ...DEFAULT_WEBHOOK_PREFERENCES },
      createdAt: new Date(record['createdAt'] as string),
      updatedAt: new Date(record['updatedAt'] as string),
    };
  }

  protected toRecord(entity: UserPreferences): DatabaseRecord {
    return {
      id: entity.id,
      userId: entity.userId,
      emailEnabled: entity.email.enabled,
      emailFrequency: entity.email.frequency,
      emailSubscribedCategories: JSON.stringify(
        entity.email.subscribedCategories,
      ),
      smsEnabled: entity.sms.enabled,
      smsPhoneNumber: entity.sms.phoneNumber,
      smsSubscribedCategories: JSON.stringify(
        entity.sms.subscribedCategories,
      ),
      webhookEnabled: entity.webhook.enabled,
      webhookUrl: entity.webhook.url,
      webhookSubscribedCategories: JSON.stringify(
        entity.webhook.subscribedCategories,
      ),
      createdAt: entity.createdAt.toISOString(),
      updatedAt: entity.updatedAt.toISOString(),
    };
  }

  /**
   * Find preferences by user ID.
   */
  findByUserId(userId: string): UserPreferences | undefined {
    const results = this.findAll((prefs) => prefs.userId === userId);
    return results[0];
  }
}
